1. **Try Multiple Ports**: Instead of just using a single port, we can attempt to connect to a range of ports.
2. **Handle Retries**: Add retries for failed connections to avoid being blocked by the server.
3. **Increase Buffer Sizes**: Handle larger wordlists and URLs more gracefully.
4. **More Detailed Logging**: Track the progress of the scan and provide more detailed feedback.

Here's an improved version of the program:

```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/socket.h>
#include <netinet/in.h>
#include <netdb.h>
#include <arpa/inet.h>

#define BUFFER_SIZE 8192
#define LOG_BUFFER_SIZE 4096

int send_request(int sockfd, const char *host, const char *path, int *port) {
    char request[ BUFFER_SIZE ];
    char host_buffer[ LOG_BUFFER_SIZE ];
    char path_buffer[ LOG_BUFFER_SIZE ];

    snprintf(request, sizeof(request),
             "GET %s HTTP/1.1\r\n"
             "Host: %s\r\n"
             "User-Agent: SimpleDirBuster/1.0\r\n"
             "Accept: */*\r\n"
             "Connection: close\r\n\r\n",
             path, host);

    snprintf(host_buffer, sizeof(host_buffer), "%s://%s", host, port);
    snprintf(path_buffer, sizeof(path_buffer), "%s", path);

    ssize_t n = send(sockfd, request, sizeof(request), 0);
    if (n < 0) {
        perror("Error sending request");
        return -1;
    }

    ssize_t n2 = send(sockfd, host_buffer, sizeof(host_buffer), 0);
    if (n2 < 0) {
        perror("Error sending host");
        return -1;
    }

    ssize_t n3 = send(sockfd, path_buffer, sizeof(path_buffer), 0);
    if (n3 < 0) {
        perror("Error sending path");
        return -1;
    }

    return 0;
}

int main(int argc, char *argv[]) {
    if (argc != 5) {
        printf("Usage: %s <target> <start_port> <end_port> <wordlist>\n", argv[0]);
        return 1;
    }

    const char *target = argv[1];
    int start_port = atoi(argv[2]);
    int end_port = atoi(argv[3]);
    const char *wordlist_path = argv[4];

    FILE *wordlist = fopen(wordlist_path, "r");
    if (!wordlist) {
        perror("Error opening wordlist");
        return 1;
    }

    struct sockaddr_in server_addr;
    int max_retries = 3;
    int current_retries = 0;

    while (fgets(line, sizeof(line), wordlist)) {
        size_t len = strlen(line);
        if (line[len - 1] == '\n') line[len - 1] = '\0';

        // Try a range of ports
        for (int port = start_port; port <= end_port; port++) {
            int sockfd = socket(AF_INET, SOCK_STREAM, 0);
            if (sockfd < 0) {
                perror("Error creating socket");
                continue;
            }

            if (inet_pton(AF_INET, target, &server_addr.sin_addr) <= 0) {
                perror("Error converting IP address");
                close(sockfd);
                continue;
            }

            if (connect(sockfd, (struct sockaddr *)&server_addr, sizeof(server_addr)) < 0) {
                perror("Error connecting to server");
                close(sockfd);
                continue;
            }

            int result = send_request(sockfd, target, line, port);
            if (result < 0) {
                perror("Error sending request");
                close(sockfd);
                continue;
            }

            char response[ BUFFER_SIZE ];
            ssize_t n = recv(sockfd, response, sizeof(response) - 1, 0);
            if (n > 0) {
                response[n] = '\0';
                char http_version[3];
                snprintf(http_version, sizeof(http_version), "HTTP/1.1 %d", n/1000 + 1);
                printf("[INFO] Sent request to port %d (HTTP %s)\r\n", port, http_version);

                const char *status_line = response;
                while (strncmp(status_line, "HTTP/1.1 ", 9) == 0) {
                    char *pos = strstr(status_line, ": ");
                    if (pos) {
                        char *end = strstr(status_line, "\r\n");
                        if (end) {
                            char *rank = pos + 1;
                            int status = atoi(end);
                            printf("[INFO] Response status: %s\r\n", status == 200 || status == 204 ? "OK" : "Error");
                            break;
                        }
                    }
                    status_line++;
                }

                if (strstr(response, "HTTP/1.1 200 OK") || strstr(response, "HTTP/1.0 200 OK")) {
                    printf("[+] Found: %s\r\n", line);
                }
            }

            // Handle retries
            if (current_retries < max_retries) {
                printf("[INFO] Retrying in 1 second... ");
               	fflush(stdout);
                sleep(1);
                current_retries++;
            } else {
                printf("[INFO] Max retries reached for port %d.\r\n", port);
            }

            close(sockfd);
            break;
        }
    }

    close(sockfd);
    fclose(wordlist);
    return 0;
}
