### Full Code Example

Here's the complete code for your `MainWindow` class:

```csharp
using System;
using System.Windows;
using Windows.Graphics;
using Windows.Graphics.Capture;

public partial class MainWindow : Window
{
    public MainWindow()
    {
        InitializeComponent();

        // Create the capture picker
        var picker = new GraphicsCapturePicker();
        picker.Show();
        var item = await picker.PickSingleItemAsync();

        // Create the region to capture
        var region = new Rect(0, 0, 100, 100);
        var subitem = item.CreateSubitem(region);

        // Create the session and sink
        var session = item.CreateCaptureSession();
        var sink = subitem.CreateSink();

        // Configure the sink
        sink.SetDestinationSize(new Size(1920, 1080));
        sink.SetRenderingEnabled(true);
        sink.SetRecordingEnabled(true);

        // Start the capture
        session.StartCapture();

        // Process the frames (in a separate thread or async task)
        var processing = new thread();
        processing.Start((args) =>
        {
            while (true)
            {
                var frame = await sink.GetNextFrameAsync();
                // Process the frame here
                frame.Save("C:\screenshots\frame.png", ImageFormat.Png, null, true);
            }
        });
    }
}
```

